import { execSync } from "child_process"; import fs from "fs";
const WP_USER=process.env.WP_USER, WP_PASS=process.env.WP_APP_PASS;
const BASE="https://dev.avesa.lt";
const AUTH="Basic "+Buffer.from(`${WP_USER}:${WP_PASS}`).toString("base64");
const repo=process.env.GH_REPO, tok=process.env.GH_TOKEN;
function commit(name,str){ const url='https://api.github.com/repos/'+repo+'/contents/screenshots/'+name; let sha=''; try{ sha=JSON.parse(execSync('curl -s -H "Authorization: Bearer '+tok+'" "'+url+'?ref=main&t='+Date.now()+'"',{encoding:'utf8'})).sha||''; }catch(e){} const body={message:'dv5',branch:'main',content:Buffer.from(str,'utf8').toString('base64')}; if(sha) body.sha=sha; fs.writeFileSync('/tmp/cbdv5.json',JSON.stringify(body)); execSync('curl -s -o /dev/null -X PUT -H "Authorization: Bearer '+tok+'" -H "Accept: application/vnd.github+json" -d @/tmp/cbdv5.json "'+url+'"',{encoding:'utf8'}); }
function exec(cmd){ try{ return execSync(cmd,{encoding:'utf8',maxBuffer:300000000,timeout:45000}); }catch(e){ return 'EXC:'+e.message.slice(0,120); } }
const code=Buffer.from("",'base64').toString('utf8');
const pcode=Buffer.from("",'base64').toString('utf8');
(async()=>{
  fs.writeFileSync('/tmp/u539.json', JSON.stringify({name:'Petshop Rinkinių Kūrimo Forma v2', code:code, scope:'admin', active:true}));
  var dr=exec('curl -sk -m 30 -X PUT -H "Authorization: '+AUTH+'" -H "Content-Type: application/json" --data-binary @/tmp/u539.json "'+BASE+'/wp-json/code-snippets/v1/snippets/539"');
  var okId=null; try{ okId=JSON.parse(dr).id; }catch(e){}
  fs.writeFileSync('/tmp/g.json', JSON.stringify({scope:'global', active:true}));
  exec('curl -sk -m 20 -X PUT -H "Authorization: '+AUTH+'" -H "Content-Type: application/json" --data-binary @/tmp/g.json "'+BASE+'/wp-json/code-snippets/v1/snippets/539"');
  fs.writeFileSync('/tmp/b557.json', JSON.stringify({name:'PSC PV5', code:pcode, scope:'global', active:true}));
  exec('curl -sk -m 20 -X PUT -H "Authorization: '+AUTH+'" -H "Content-Type: application/json" --data-binary @/tmp/b557.json "'+BASE+'/wp-json/code-snippets/v1/snippets/557"');
  var r=exec('curl -sk -m 40 "'+BASE+'/?psc_pv5=1&k=ps2026"');
  var m=r.match(/(\{.*\})/s); commit('probe_v5.json', m?m[0]:(r||'').slice(0,700));
  exec('curl -sk -m 20 -X DELETE -H "Authorization: '+AUTH+'" "'+BASE+'/wp-json/code-snippets/v1/snippets/557"');
  fs.writeFileSync('/tmp/a.json', JSON.stringify({scope:'admin', active:true}));
  var back=exec('curl -sk -m 20 -X PUT -H "Authorization: '+AUTH+'" -H "Content-Type: application/json" --data-binary @/tmp/a.json "'+BASE+'/wp-json/code-snippets/v1/snippets/539"');
  var scopeNow=''; try{ scopeNow=JSON.parse(back).scope; }catch(e){}
  commit('scope_v5.json', JSON.stringify({deploy_id:okId, scope_539_now:scopeNow}));
  console.log('done');
})();
